def test_path_export_multiband(tmpdir):
    """Check that PATH export correctly handles C+L
    """
    equipment = load_equipment(DATA_DIR / 'eqpt_config_multiband.json', EXTRA_CONFIGS)
    network = load_network(DATA_DIR / 'testTopology_C+L.json', equipment)

    # Lannion To Rennes is fully designin C+L but not the rest of the network, which must be designed for C band.
    # let's use 80 channels @0dBm to be under max power of amps (21 dBm)
    p_db = 0.0
    build_network(network, equipment, pathrequest(p_db, 80))
    oms_list = build_oms_list(network, equipment)

    rqs = [request()]
    dsjn = []
